using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService : IHostedService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly IWebHostEnvironment _env;

    public ModelTrainerService(ILogger<ModelTrainerService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _env = env;
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(_env.ContentRootPath, "Data", "tickets.csv");
        var modelPath = Path.Combine(_env.ContentRootPath, "Data", "TicketModel.zip");

        var dataView = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

        var pipeline = BuildPipeline(mlContext);

        // Train on split for evaluation
        var trainedModel = pipeline.Fit(split.TrainSet);
        var predictions = trainedModel.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("Macro Accuracy: {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("Micro Accuracy: {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("LogLoss: {LogLoss:F4}", metrics.LogLoss);

        // Train final model on all data and save
        var finalModel = pipeline.Fit(dataView);
        mlContext.Model.Save(finalModel, dataView.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;

    private static IEstimator<ITransformer> BuildPipeline(MLContext mlContext)
    {
        return mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", "Priority"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public TicketController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public IActionResult Classify([FromBody] ClassifyRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var categories = new[] { "Billing", "General", "Technical" };
        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length && i < categories.Length; i++)
        {
            confidence[categories[i]] = prediction.Score[i];
        }

        return Ok(new
        {
            predictedCategory = prediction.PredictedLabel,
            confidence
        });
    }
}

public class ClassifyRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

